WITH cover_map AS (
  SELECT *
  FROM image_sync_payload,
       jsonb_to_recordset(data->'covers') AS x(title text, image text)
)
UPDATE "Post" p
SET cover_image_url = cm.image,
    updated_at = NOW()
FROM cover_map cm
WHERE regexp_replace(btrim(p.title_en), '[[:space:]]+', ' ', 'g')
    = regexp_replace(btrim(cm.title), '[[:space:]]+', ' ', 'g');

WITH item_map AS (
  SELECT *
  FROM image_sync_payload,
       jsonb_to_recordset(data->'items') AS x(title text, position bigint, image text)
), rebuilt AS (
  SELECT
    p.id,
    jsonb_agg(
      CASE
        WHEN elem->>'type' = 'restaurant' THEN
          COALESCE(
            (
              SELECT jsonb_set(elem, '{data,coverUrl}', to_jsonb(im.image), true)
              FROM item_map im
              WHERE regexp_replace(btrim(im.title), '[[:space:]]+', ' ', 'g')
                  = regexp_replace(btrim(p.title_en), '[[:space:]]+', ' ', 'g')
                AND im.position = ord
              LIMIT 1
            ),
            elem
          )
        ELSE elem
      END
      ORDER BY ord
    ) AS next_blocks
  FROM "Post" p
  CROSS JOIN LATERAL jsonb_array_elements(COALESCE(p.content_blocks_json::jsonb, '[]'::jsonb)) WITH ORDINALITY AS t(elem, ord)
  GROUP BY p.id
)
UPDATE "Post" p
SET content_blocks_json = r.next_blocks,
    updated_at = NOW()
FROM rebuilt r
WHERE p.id = r.id;

COMMIT;
